#include <bits/stdc++.h>
using namespace std;
struct Edge{
    int to;
    string str;
};
int n,d[1003][2],use[1003];
string s[1003];
vector<Edge> g[26];
stack<string> path;
bool cmp(Edge x,Edge y){
	return x.str<y.str; 
}
void dfs(int x){
	int len=g[x].size();
	for(int i=use[x];i<len;i=use[x]){
        use[x]++;
		dfs(g[x][i].to);
		path.push(g[x][i].str);
	}
}
void output(){
	for(int i=1;i<=n;i++){
		if(i-1)
			printf(".");
		cout<<path.top();
		path.pop();
	}
}
int main(){
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
        cin>>s[i];
    for(int i=1;i<=n;i++){
        d[s[i][0]-'a'][1]++;
        g[s[i][0]-'a'].push_back({s[i][s[i].size()-1]-'a',s[i]});
        d[s[i][s[i].size()-1]-'a'][0]++;
    }
    for(int i=0;i<26;i++)
    	sort(g[i].begin(),g[i].end(),cmp);
    
    int s=-1,e=-1;
    for(int i=0;i<26;i++)
        if(d[i][0]!=d[i][1]){
            if(abs(d[i][0]-d[i][1])>1){
            	printf("***");
                return 0;
			}
            if(d[i][0]>d[i][1]){
                if(e+1){
                    printf("***");
                    return 0;
                }else
                    e=i;
            }else{
                if(s+1){
                	printf("***");
                    return 0;
                }else
                    s=i;
            }
        }
    if(s+1)
        dfs(s);
    else
    	for(int i=0;i<26;i++)
    		if(d[i][1]){
    			dfs(i);
    			break;
    		}
    if(path.size()!=n)
    	printf("***");
    else
    	output();
    return 0;
}
